def rgb(r, g, b):
    return f"\033[38;2;{r};{g};{b}m"

RST   = "\033[0m"
BOLD  = "\033[1m"
DIM   = "\033[2m"

P1 = rgb(130, 80, 230)
P2 = rgb(0, 206, 201)
P3 = rgb(0, 230, 118)
P4 = rgb(255, 82, 82)
P5 = rgb(255, 215, 64)
P6 = rgb(108, 92, 231)
P7 = rgb(85, 85, 85)
P8 = rgb(200, 200, 200)
W  = rgb(255, 255, 255)

def gradient_text(text, r1, g1, b1, r2, g2, b2):
    out = []
    n = max(len(text) - 1, 1)
    for i, ch in enumerate(text):
        t = i / n
        r = int(r1 + (r2 - r1) * t)
        g = int(g1 + (g2 - g1) * t)
        b = int(b1 + (b2 - b1) * t)
        out.append(f"{rgb(r, g, b)}{ch}")
    out.append(RST)
    return "".join(out)

def grad(text):
    return gradient_text(text, 130, 80, 230, 0, 206, 201)

def grad2(text):
    return gradient_text(text, 0, 206, 201, 0, 230, 118)

def grad3(text):
    return gradient_text(text, 130, 80, 230, 255, 100, 180)


