def box_top(w=58):
    return f"  {P6}‚ē≠{'‚ĒÄ' * w}‚ēģ{RST}"

def box_mid(w=58):
    return f"  {P6}‚Ēú{'‚ĒÄ' * w}‚Ē§{RST}"

def box_bot(w=58):
    return f"  {P6}‚ēį{'‚ĒÄ' * w}‚ēĮ{RST}"

def box_line(text, w=58):
    clean = re.sub(r'\033\[[^m]*m', '', text)
    pad = w - len(clean)
    if pad < 0: pad = 0
    return f"  {P6}‚Ēā{RST} {text}{' ' * pad}{P6}‚Ēā{RST}"

def box_empty(w=58):
    return f"  {P6}‚Ēā{' ' * w}‚Ēā{RST}"


# ‚ĒÄ‚ĒÄ‚ĒÄ Chrome driver singleton ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ

_driver = None
_driver_lock = threading.Lock()

def get_driver():
    global _driver
    with _driver_lock:
        if _driver is not None:
            try:
                _driver.title
                return _driver
            except:
                _driver = None

        print(f"  {P2}initializing chrome...{RST}", end="", flush=True)
        opts = uc.ChromeOptions()
        opts.add_argument("--headless=new")
        opts.add_argument("--no-sandbox")
        opts.add_argument("--disable-dev-shm-usage")
        opts.add_argument("--disable-gpu")
        opts.add_argument("--window-size=1280,720")
        opts.add_argument("--log-level=3")
        opts.add_argument("--silent")

        try:
            _driver = uc.Chrome(options=opts, use_subprocess=True)
            _driver.set_page_load_timeout(20)
            print(f"\r  {P3}chrome ready.{' ' * 30}{RST}")
            return _driver
        except Exception as e:
            print(f"\r  {P4}chrome failed: {e}{' ' * 20}{RST}")
            return None


def close_driver():
    global _driver
    with _driver_lock:
        if _driver:
            try:
                _driver.quit()
            except:
                pass
            _driver = None


# ‚ĒÄ‚ĒÄ‚ĒÄ Krunker lookup via Selenium ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ

PROFILE_URL = "https://krunker.io/social.html?p=profile&q={}"
CLAN_URL    = "https://krunker.io/social.html?p=clan&q={}"

def check_username(name):
    """Returns (status, info_dict). status: 'available'|'taken'|'error'"""
    driver = get_driver()
    if not driver:
        return "error", {"detail": "chrome unavailable"}

    try:
        url = PROFILE_URL.format(name)
        driver.get(url)

        # wait for page to load and social content to render
        time.sleep(3)

        # check for various indicators
        page_src = driver.page_source

        # "Player not found" or similar
        not_found_patterns = [
            "Player not found",
            "player not found",
            "User not found",
            "not found",
            "Invalid Player",
        ]

        # look for profile data indicators
        has_profile = False
        info = {}

        # check page title / content
        for pattern in not_found_patterns:
            if pattern.lower() in page_src.lower():
                # but make sure it's not just in a script or other noise
                # check if the actual profile container shows "not found"
                try:
                    body_text = driver.find_element(By.TAG_NAME, "body").text
                    if pattern.lower() in body_text.lower():
                        return "available", {}
                except:
                    pass

        # try to find profile stats elements
        try:
            # krunker social page uses specific class names for stats
            body_text = driver.find_element(By.TAG_NAME, "body").text

            if not body_text.strip() or len(body_text.strip()) < 20:
                # page didn't load properly
                return "error", {"detail": "page load failed"}

            # look for level indicator, KR, kills, etc.
            level_match = re.search(r'(?:LVL|Level)\s*[:\s]?\s*(\d+)', body_text, re.IGNORECASE)
            kills_match = re.search(r'(?:Kills)\s*[:\s]?\s*([\d,]+)', body_text, re.IGNORECASE)
            deaths_match = re.search(r'(?:Deaths)\s*[:\s]?\s*([\d,]+)', body_text, re.IGNORECASE)
            score_match = re.search(r'(?:Score)\s*[:\s]?\s*([\d,]+)', body_text, re.IGNORECASE)
            clan_match = re.search(r'\[(\w+)\]', body_text)

            if level_match:
                info["level"] = level_match.group(1)
                has_profile = True
            if kills_match:
                info["kills"] = kills_match.group(1)
                has_profile = True
            if deaths_match:
                info["deaths"] = deaths_match.group(1)
                has_profile = True
            if score_match:
                info["score"] = score_match.group(1)
                has_profile = True
            if clan_match:
                info["clan"] = clan_match.group(1)

            if has_profile:
                return "taken", info

            # if we found some text but no stats, check for clear "not found"
            if any(x in body_text.lower() for x in ["not found", "invalid", "error"]):
                return "available", {}

            # ambiguous ‚ÄĒ page loaded but no clear signal
            # check if there's meaningful profile content
            if len(body_text.strip()) > 100:
                return "taken", info
            else:
                return "available", {}

        except Exception as e:
            return "error", {"detail": str(e)}

    except Exception as e:
        return "error", {"detail": str(e)}


def check_clan(tag):
    """Returns (status, info_dict)."""
    driver = get_driver()
    if not driver:
        return "error", {"detail": "chrome unavailable"}

    try:
        url = CLAN_URL.format(tag)
        driver.get(url)
        time.sleep(3)

        page_src = driver.page_source
        info = {}

        try:
            body_text = driver.find_element(By.TAG_NAME, "body").text

            if not body_text.strip() or len(body_text.strip()) < 20:
                return "error", {"detail": "page load failed"}

            not_found = ["clan not found", "not found", "invalid clan"]
            for pattern in not_found:
                if pattern in body_text.lower():
                    return "available", {}

            # look for clan data
            members_match = re.search(r'(?:Members)\s*[:\s]?\s*(\d+)', body_text, re.IGNORECASE)
            level_match = re.search(r'(?:LVL|Level)\s*[:\s]?\s*(\d+)', body_text, re.IGNORECASE)

            if members_match:
                info["members"] = members_match.group(1)
            if level_match:
                info["level"] = level_match.group(1)

            if members_match or level_match or len(body_text.strip()) > 100:
                return "taken", info
            else:
                return "available", {}

        except Exception as e:
            return "error", {"detail": str(e)}

    except Exception as e:
        return "error", {"detail": str(e)}


# ‚ĒÄ‚ĒÄ‚ĒÄ Result formatting ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ

def fmt_available(name):
    return f"  {P3}  ‚úď  {W}{BOLD}{name:<20}{RST} {P3}‚Ēā AVAILABLE{RST}"

def fmt_taken(name, info=None):
    extra = ""
    if info:
        parts = []
        if info.get("level"): parts.append(f"lvl:{info['level']}")
        if info.get("kills"): parts.append(f"k:{info['kills']}")
        if info.get("clan"):  parts.append(f"clan:{info['clan']}")
        if info.get("members"): parts.append(f"members:{info['members']}")
        if parts:
            extra = f" {P7}({', '.join(parts)}){RST}"
    return f"  {P4}  ‚úó  {W}{BOLD}{name:<20}{RST} {P4}‚Ēā TAKEN{RST}{extra}"

def fmt_error(name, detail=""):
    return f"  {P5}  ‚ö†  {W}{BOLD}{name:<20}{RST} {P5}‚Ēā ERROR{RST} {P7}{detail}{RST}"


# ‚ĒÄ‚ĒÄ‚ĒÄ Spinner ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ

SPINNER = ["‚†č", "‚†ô", "‚†Ļ", "‚†ł", "‚†ľ", "‚†ī", "‚†¶", "‚†ß", "‚†á", "‚†Ź"]

def spin(idx):
    return f"{P2}{SPINNER[idx % len(SPINNER)]}{RST}"


# ‚ĒÄ‚ĒÄ‚ĒÄ Progress bar ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ

def progress_bar(current, total, width=30):
    pct = current / total if total else 0
    filled = int(width * pct)
    bar = ""
    for i in range(width):
        t = i / max(width - 1, 1)
        r = int(130 + (0 - 130) * t)
        g = int(80 + (230 - 80) * t)
        b = int(230 + (118 - 230) * t)
        bar += f"{rgb(r, g, b)}{'‚Ėą' if i < filled else '‚ĖĎ'}{RST}"
    return f"  {P7}[{RST}{bar}{P7}]{RST} {W}{current}{P7}/{RST}{W}{total}{RST}  {P2}{int(pct*100)}%{RST}"


# ‚ĒÄ‚ĒÄ‚ĒÄ Menu actions ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ

def single_check(check_type):
    label = "clan tag" if check_type == "clan" else "username"
    check_fn = check_clan if check_type == "clan" else check_username

    print()
    print(box_top())
    print(box_line(f"{P2}{BOLD}Single {label.title()} Check{RST}"))
    print(box_bot())
    print()

    name = input(f"  {P6}>{RST} enter {label}: {W}").strip()
    print(RST, end="")
    if not name:
        print(f"  {P4}no input.{RST}")
        return

    sys.stdout.write(f"\r  {spin(0)} checking {P8}{name}{RST}...")
    sys.stdout.flush()

    status, info = check_fn(name)

    sys.stdout.write(f"\r{' ' * 70}\r")
    if status == "available":
        print(fmt_available(name))
    elif status == "taken":
        print(fmt_taken(name, info))
    else:
        print(fmt_error(name, info.get("detail", "")))

    if status == "taken" and info:
        print()
        print(f"  {P7}{'‚ĒÄ' * 46}{RST}")
        for k, v in info.items():
            if k == "detail": continue
            print(f"    {P7}{k:<14}{RST} {W}{v}{RST}")
        print(f"  {P7}{'‚ĒÄ' * 46}{RST}")
    print()


def bulk_check(check_type):
    label = "clan tags" if check_type == "clan" else "usernames"
    check_fn = check_clan if check_type == "clan" else check_username

    print()
    print(box_top())
    print(box_line(f"{P2}{BOLD}Bulk {label.title()} Check{RST}"))
    print(box_mid())
    print(box_line(f"{P7}enter names one per line, empty line to start{RST}"))
    print(box_line(f"{P7}or paste a comma/space separated list{RST}"))
    print(box_bot())
    print()

    names = []
    print(f"  {P6}>{RST} enter {label} {P7}(empty line = go):{RST}")
    while True:
        try:
            line = input(f"    {P7}‚Ēā{RST} {W}").strip()
            print(RST, end="")
        except EOFError:
            break
        if not line:
            break
        for part in line.replace(",", " ").split():
            part = part.strip()
            if part and part not in names:
                names.append(part)

    if not names:
        print(f"  {P4}no names provided.{RST}")
        return

    if len(names) > 100:
        names = names[:100]
        print(f"  {P5}capped at 100 names.{RST}")

    print()
    print(f"  {P6}{'‚ĒÄ' * 50}{RST}")
    print(f"  {P2}checking {W}{len(names)}{P2} {label}...{RST}")
    print(f"  {P6}{'‚ĒÄ' * 50}{RST}")
    print()

    stats = {"available": 0, "taken": 0, "errors": 0}
    available_names = []

    for i, name in enumerate(names):
        sys.stdout.write(f"\r{progress_bar(i, len(names))}  {spin(i)} {P7}{name:<16}{RST}")
        sys.stdout.flush()

        status, info = check_fn(name)

        sys.stdout.write(f"\r{' ' * 80}\r")
        if status == "available":
            print(fmt_available(name))
            stats["available"] += 1
            available_names.append(name)
        elif status == "taken":
            print(fmt_taken(name, info))
            stats["taken"] += 1
        else:
            print(fmt_error(name, info.get("detail", "")))
            stats["errors"] += 1

        if i < len(names) - 1:
            time.sleep(0.5)

    print()
    print(progress_bar(len(names), len(names)))
    print()

    print(box_top(40))
    print(box_line(f"{BOLD}Results Summary{RST}", 40))
    print(box_mid(40))
    print(box_line(f"{P3}  available:  {W}{stats['available']}{RST}", 40))
    print(box_line(f"{P4}  taken:      {W}{stats['taken']}{RST}", 40))
    print(box_line(f"{P5}  errors:     {W}{stats['errors']}{RST}", 40))
    print(box_bot(40))

    if available_names:
        print()
        print(f"  {P3}{BOLD}available {label}:{RST}")
        for n in available_names:
            print(f"    {P3}‚Üí{RST} {W}{n}{RST}")
    print()


def wordlist_check(check_type):
    label = "clan tags" if check_type == "clan" else "usernames"
    check_fn = check_clan if check_type == "clan" else check_username

    print()
    print(box_top())
    print(box_line(f"{P2}{BOLD}Wordlist {label.title()} Check{RST}"))
    print(box_mid())
    print(box_line(f"{P7}provide path to a .txt file (one name per line){RST}"))
    print(box_bot())
    print()

    filepath = input(f"  {P6}>{RST} file path: {W}").strip().strip('"').strip("'")
    print(RST, end="")

    if not os.path.isfile(filepath):
        print(f"  {P4}file not found: {filepath}{RST}")
        return

    with open(filepath, "r", encoding="utf-8", errors="ignore") as f:
        names = [line.strip() for line in f if line.strip()]
    names = list(dict.fromkeys(names))

    if not names:
        print(f"  {P4}file is empty.{RST}")
        return

    print(f"  {P7}loaded {W}{len(names)}{P7} names from file.{RST}")

    if len(names) > 500:
        names = names[:500]
        print(f"  {P5}capped at 500 names.{RST}")

    print()
    print(f"  {P6}{'‚ĒÄ' * 50}{RST}")
    print(f"  {P2}checking {W}{len(names)}{P2} {label}...{RST}")
    print(f"  {P6}{'‚ĒÄ' * 50}{RST}")
    print()

    stats = {"available": 0, "taken": 0, "errors": 0}
    available_names = []

    for i, name in enumerate(names):
        sys.stdout.write(f"\r{progress_bar(i, len(names))}  {spin(i)} {P7}{name:<16}{RST}")
        sys.stdout.flush()

        status, info = check_fn(name)

        sys.stdout.write(f"\r{' ' * 80}\r")
        if status == "available":
            print(fmt_available(name))
            stats["available"] += 1
            available_names.append(name)
        elif status == "taken":
            print(fmt_taken(name, info))
            stats["taken"] += 1
        else:
            print(fmt_error(name, info.get("detail", "")))
            stats["errors"] += 1

        if i < len(names) - 1:
            time.sleep(0.5)

    print()
    print(progress_bar(len(names), len(names)))
    print()

    print(box_top(40))
    print(box_line(f"{BOLD}Results Summary{RST}", 40))
    print(box_mid(40))
    print(box_line(f"{P3}  available:  {W}{stats['available']}{RST}", 40))
    print(box_line(f"{P4}  taken:      {W}{stats['taken']}{RST}", 40))
    print(box_line(f"{P5}  errors:     {W}{stats['errors']}{RST}", 40))
    print(box_bot(40))

    if available_names:
        print()
        print(f"  {P3}{BOLD}available {label}:{RST}")
        for n in available_names:
            print(f"    {P3}‚Üí{RST} {W}{n}{RST}")

        print()
        save = input(f"  {P6}>{RST} save available to file? {P7}(y/n):{RST} {W}").strip().lower()
        print(RST, end="")
        if save in ("y", "yes"):
            out_path = filepath.rsplit(".", 1)[0] + "_available.txt"
            with open(out_path, "w", encoding="utf-8") as f:
                f.write("\n".join(available_names))
            print(f"  {P3}saved to {W}{out_path}{RST}")
    print()


