def main():
    os.system("cls" if sys.platform == "win32" else "clear")
    print_banner()

    while True:
        print_menu()
        print()
        choice = input(f"  {P6}>{RST} select: {W}").strip()
        print(RST, end="")

        if choice == "1":
            single_check("username")
        elif choice == "2":
            single_check("clan")
        elif choice == "3":
            bulk_check("username")
        elif choice == "4":
            bulk_check("clan")
        elif choice == "5":
            wordlist_check("username")
        elif choice == "6":
            wordlist_check("clan")
        elif choice == "0":
            close_driver()
            print(f"\n  {grad('bye.')}\n")
            break
        else:
            print(f"  {P4}invalid option.{RST}\n")

if __name__ == "__main__":
    try:
        main()
    except KeyboardInterrupt:
        close_driver()
        print(f"\n\n  {grad('interrupted.')}\n")
